INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1109_L013$$, 2026, $$The M41A7 Saber weapon system is a combat proven system that provides long-range, lethal anti-armor precision assault capability for the United States Marine Corps Infantry, and Light Armored
 Reconnaissance Battalions across modern operational environments. The M41A7 is the replacement for the M220 Tube-launched, optically tracked, Wire/Wireless-guided (TOW) 2 weapon system. Global
 Positioning System based location detection, and an altitude determination subsystem generate a 10-digit grid coordinate of a target's position, and superior surveillance capability enables the warfighter to
 identify targets at long range and engage with TOW missiles or other weapon systems.

 TOW missiles (BGM-71 Series) are the munition for the M41A7 system. The TOW missile is a highly lethal, cost effective, interoperable, multi-purpose anti-armor round that is used in either direct-fire or "fly-
 over, shoot down" mode against field fortifications and structures. In its current configuration, the combination of the M41A7 and the TOW missile provides the capability to defeat armored vehicles, bunkers, and
 buildings at extended ranges in all battlefield conditions.

 The M41A7 is mounted on a variety of combat vehicle systems including the Joint Lightweight Tactical Vehicle, High Mobility Multipurpose Wheeled Vehicle, Mine Resistant Ambush Protected Vehicle, and Light
 Armored Vehicle - Anti-Tank, as well as having the capability for ground mounted operations.

 The U.S. Army Program Executive Office Missiles and Space (PEO MS) Tactical Aviation & Ground Munitions TOW Product Office is the lead for this joint program with the Marine Corps. These munitions have a
 procurement lead-time of 24-36 months.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                     Date: April 2026
