INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L003$$, 2026, $$Joint Strike Fighter (JSF) program will enhance and field a family of aircraft that meets the needs of DoD and allies with three air vehicle variants including: the F-35A Conventional Take Off and Landing
 (CTOL) variant, the F-35B Short Take-Off and Vertical Landing (STOVL) variant, and the F-35C Carrier Variant (CV) delivering commonality among the three variants to minimize life cycle costs. This is a joint
 program with no executive service. Service Acquisition Executive (SAE) authority alternates between the Department of the Navy (DoN) and the Department of the Air Force (DAF) and currently resides with
 the Navy. The F-35 is the next generation of strike fighters and provides increased aero-performance, stealth signature, and countermeasures. Its advanced avionics, data links, and adverse weather precision
 targeting incorporates the latest technology available. The F-35 has increased range with internal fuel and can employ superior weaponry over existing aircraft. The highly supportable, affordable, state of the
 art aircraft commands and maintains global air superiority. The production cost and quantities are interdependent due to sole source air vehicle and propulsion contracts. United States Air Force (USAF) regular
 procurement commenced in FY 2007, DoN regular procurement commenced in FY 2008. Funding for this exhibit contained in PE 0207142F.

 Notes:

 USAF Initial Operational Capability (IOC) occurred on 2 August 2016 and the Full Rate Production (FRP) occurred on 12 March 2024.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":3,"src_title":"F-35","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Aircraft Procurement Vol I.pdf$$, 55, 55, $$2b34592e22b165e8$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
