INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L009$$, 2026, $$Funding is for the procurement of various Platform-in-a-Box (PIAB) and platform specific battlestation training equipment to include, but not limited to, hardware, software, licenses, peripheral equipment and
 sub-systems, visual display system, inital spares, and the integration of those systems into the Joint Simulation Environment (JSE) battlespace. PIABs and battlestations will be used at various Joint Integrated
 Test & Training Center (JITTC) locations including, but not limited to; Nellis AFB (JITTC-N) and Joint Base Elmendorf-Richardson (JITTC-E), leveraging the JSE. PIABs and battlestations will support training
 operations, large force exercises, and local small force events. The intent is to replicate and expand the current digital test & training range capabilities allowing multiple dissimilar PIABs and battlestations to
 operate in a common environment without concern for airspace constraints, threat density, and outside surveillance, while protecting friendly capability Tactics, Techniques, and Procedures (TTPs) and future
 capabilities.

 JSE leverages 5th+ Generation Operational Test and Evaluation (OT&E) capability to improve TTPs in an operationally relevant environment. JITTCs support large force exercises and the United States Air
 Force Warfare Center (USAFWC), Weapons Instructor Course (WIC) syllabus through Weapon School Integration (WSINT). The high-fidelity simulator training to be provided by JSE improves the throughput
 capacity of Formal Training Unit (FTU) and joint war fighter tactical readiness. Funding may also be used to address Diminishing Manufacturing Sources (DMS) issues, obsolescence resolution and similar
 emerging requirements, as well as overarching programmatic support. This requirement (or modification) supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D.
 Funding for this exhibit is contained in PE 0207606F.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":9,"src_title":"Joint Simulation Environment","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Aircraft Procurement Vol I.pdf$$, 85, 85, $$88cbd449671e2548$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1109_L053$$, 2026, $$The JLTV and companion trailer is the Marine Corps' premier platform for modernizing the light fleet, replacing the HMMWV, and supporting Force Design capabilities. Funding supports the JLTV Family of
 Vehicles (FoV) to include the development and testing of Command, Control, Communications, Computers, & Intelligence (C4I) for integration with the JLTV. JLTV is a joint program between the U.S. Army and
 the U.S. Marine Corps, of which the U.S. Army is the procurement lead and primary inventory control authority (PICA) while the Marine Corps is the requirement lead. The JLTV FoV is capable of performing
 multiple mission roles designed to provide protected, sustained, and networked mobility for personnel and payloads across the full Range of Military Operations.

 Army, as the procurement lead, competitively issued the follow-on production award to AM General LLC on 09 Feb 2023 as a single award five-year requirements contract with five one-year options.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                     Date: April 2026
