INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1506_L012_v24$$, 2027, $$The F/A-18E/F Naval Strike Fighter is a twin-engine, mid-wing, multi-mission tactical aircraft. F/A-18E/F can be missionized through selected use of external equipment to accomplish specific fighter or attack
 missions. This capability allows the Operational Commander more flexibility in employing his tactical aircraft in a dynamic scenario. The primary design mission for the F/A-18E/F is a strike fighter which includes
 the traditional applications, such as fighter escort and fleet air defense, combined with the attack applications, such as interdiction and close air support. Since the same airframe systems are used on attack
 missions as well as fighter missions, excellent fighter and self defense capability is retained.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                      Date: April 2026
