INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1506_L034$$, 2027, $$The U.S. Marine Corps (USMC) UC-12W Operational Support Airlift aircraft is a FAA type-certified modern commercial cargo/passenger transport aircraft that will replace the USMC UC-12F/M and UC-35 C/D
 aircraft in performing Operational Support Airlift (OSA) missions. The OSA mission provides transportation for high priority passengers and cargo with time, place or mission sensitive requirements. The aircraft
 will be capable of operating out of short, unimproved airfields; carry a minimum of nine passengers or light cargo; or carry a combination of passengers and cargo. The aircraft will be delivered with the following
 military unique systems: Ultra High Frequency (UHF) radio, Tactical Air Navigation (TACAN) radio, Identification Friend or Foe/Selective Identification Feature (IFF/SIF), and Aircraft Survivability Equipment
 (ASE).

 In "Prior Years", in addition to the ten aircraft shown above, two Other Support Aircraft (UC-12W) were procured for the USMC Reserves using FY07 & FY08 National Guard & Reserve Equipment Account
 (NGREA) funding.

 In July 2023, the USMC increased the UC-12W Program of Record (POR) quantity from 12 to 30 aircraft to support operational requirement.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                       Date: April 2026
