INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_0300_L062$$, 2026, $$The Other Major Equipment budget line-item supports the following mission requirements:

 - Ongoing Nuclear Arms Control Technology (NACT) program operational responsibilities, including recapitalization of the U.S. International Monitoring System stations in support of the United States and
 Department of War (DoW) objectives related to implementation, monitoring, and verification for nuclear arms control activities;

 - Defense Stockpile Management System (DSMS) modernization. DSMS contains the Defense Integration and Management of Nuclear Data Services (DIAMONDS), an information system providing nuclear
 weapons stockpile tracking, management, and nuclear weapons reporting necessary to support the DoW Nuclear Weapons Stockpile Database of record and other nuclear weapons sustainment and
 management applications;

 - Material Handling Equipment (MHE) to support missions in the United States and overseas. MHE refers to various equipment for handling supplies with greater ease and economy, to include but not limited to
 forklifts. The equipment is operated on rocky and unpaved terrain, resulting in shortened life cycles and increased maintenance;

 - Lifecycle replacement and modernization of end-of-life mission IT infrastructure to ensure greater than 99% service availability, sustainment of network Authorizations to Operate, remediation of cybersecurity
 vulnerabilities, modernization of DTRA's Countering Weapons of Mass Destruction (CWMD) data platform, Artificial Intelligence and Machine Learning environments, and Development, Security, and Operations
 (DevSecOps) platform; and

 - Joint Radiation Detection System (RDS) to train all service members at the DoW Nuclear Weapons School to operate in a realistic combined joint radiological environment.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Defense Threat Reduction Agency                                                                                          Date: April 2026
