INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_0300_L092$$, 2027, $$This P-1 Line Item is part of the Military Intelligence Program (MIP). It includes purchases that provide for Intelligence, Surveillance, and Reconnaissance (ISR) in support of irregular warfare operations. This
 line funds Special Operations-peculiar (SO-p) modifications and rapid fielding to crewed ISR aircraft. Primary mission emphasis is on signals intelligence, imagery, target acquisition, threat warning, threat
 identification, and surveillance missions. Includes avionics, sensor maintenance, SO-p support equipment, communication systems, common datalink systems, training, trainers, and mission training devices.

 Funding for this P-1 line item ended in FY 2025, as USSOCOM divested of the SOCOM Tactical Airborne Multi-Sensor Platform.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 United States Special Operations Command                                                                                Date: April 2026
