INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1508_L008$$, 2026, $$Jet-Assisted Take-Off (JATO) / Rocket-Assisted Take-Off (RATO) are solid propellant rocket motors used to launch subsonic aerial targets into controlled flight. Subsonic aerial targets are used in Fleet Live
 Fire with a Purpose pre-deployment force generation certification events, Naval Sea Systems Command's post-availability Combat System Ship Qualification Test (CSSQT) program and developmental and
 operational test and evaluation in support of Navy and DoW acquisition programs. The JATO / RATO family of rocket motors consists of the MK-23 and MK-129 in support of BQM-34 launches, the MK-117 in
 support of BQM-74 launches, and the MK-85 in support of BQM-177 launches. MK-129 JATO Procurement includes required MK-296 Igniters. MK-129 is developed under PE 0604258N.

 JATO / RATO quantities are tied to BQM-177 and BQM-34 procurements, target operating activity inventories and annual target presentation requirements of the fleet for training and post-availability combat
 systems checks, Navy and DoW acquisition programs, and fleet exercise programs. Funding also supports production engineering support, integrated logistics support, ordnance safety, product improvements,
 quality assurance and lot acceptance testing.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                     Date: April 2026
