INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1109_L021$$, 2027, $$Electro Magnetic Spectrum Operations (EMSO): The EMSO funding line includes the current operational solution, Multi-Function Electronic Warfare (MFEW) Family of Systems (FoS) which adds significant
 additional force protection including Counter-Unmanned Aircraft System (CUAS) and rudimentary offensive Electronic Warfare (EW) capabilities that will support operations past FY 2030. The future operational
 solution will be fulfilled by a future system, a critical Force Design program that enables the Expeditionary Advanced Base Operations (EABO) construct by facilitating ground-based Electronic Warfare (EW).

 A future system will be developed using the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance(C5ISR)/EW Modular Open Suite of Standards (CMOSS)
 and Sensor Open Systems Architecture (SOSA) standards, in coordination with the Army, Navy, and Air Force. This will provide an open architecture of non-proprietary hardware and software platforms that will
 eliminate some proprietary equipment Marines currently carry, which will lower the weight and power requirements, reduce training burdens, lower procurement costs, and reduce sustainment costs. The future
 system will be employed throughout the Fleet Marine Force and provide coordinated EW in support of Fires and Maneuver, Force Protection, Spectrum Management, and Battlespace Awareness.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                     Date: April 2026
