INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1109_L038$$, 2026, $$Repair and Test Equipment Budget Line Item provides repair and test equipment consisting of more than 200 different items required to support the operation and maintenance of Marine Corps ground based
 weapon systems and major end items, including Marine Air-Ground Task Force (MAGTF) Logistics Support Systems (MLS2), a key CMC Force Design program enabling readiness while conducting Littoral
 Operations in Contested Environments (LOCE). These capabilities will enable ground, ordinance, and communication maintainers to perform organic maintenance activities on various Marine Corps platforms
 across widely dispersed locations that will increase the ability to sustain operational readiness levels. This portfolio also includes repair and test equipment supporting air defense systems, C2 in a degraded
 environment system, close combat lethality systems, and information warfare. It includes items such as tool kits, shop sets, manual and automatic test equipment, metrology and calibration equipment, and
 Advanced Manufacturing Systems (AMS) that includes Expeditionary Fabrication Equipment (XFAB), Tactical Fabrication Equipment (TACFAB) and Advanced Integrated Mobile Machine Shop (AIMMS).

 The following acquisition programs fall under the repair and test equipment budget line: General Purpose Tools and Test Systems (GPT&TS); MAGTF Logistics Support Systems (MLS2); Advanced
