INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L075$$, 2026, $$The four-engine E-3 is a modified Boeing 707 airframe which carries airborne radar and provides all-altitude air surveillance, threat warning, and control of theater air forces, the fleet is comprised of 16 aircrafts.
 Totals include funding for Airborne Warning and Control System (AWACS) Upgrades. Funding may be used to address Diminishing Manufacturing Sources (DMS) issues for the overall E-3 weapon system to
 include aircraft, simulators, and training devices.

 Life of Type (LoT) buy to procure parts for retrofit of Production jets.

 Air Education and Training Command (AETC) funding is contribution to the Command to train pilots, air battle managers, and maintainers on unique E-3 systems.

 AWACS Communication Integration Program (ACIP) will provide Second Generation Anti-Jam Tactical UHF Radio for NATO (SATURN) capability by replacing the existing ARC-204 Have Quick II with ARC-210
 Gen 6 radios capable of communicating via the existing and additional military waveforms. There are 16 total aircraft in the inventory. The first prototype kit was procured and installed with FY23 RDT&E funds.
 There will be 15 Production aircraft that will receive the ACIP modification with a four (4) radio configuration.

 Funding is decreased due to transitioning efforts from procuring and integrating ACIP equipment to installation efforts and interim sustainment effort.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":75,"src_title":"E-3","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Aircraft Procurement Vol II.pdf$$, 575, 575, $$64333a9d6e51734e$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L080$$, 2026, $$This line item funds modifications to UH-1N and TH-1H aircraft. The two-engine UH-1N is a light, utility helicopter primarily used for missile site and range support and distinguished visitor airlift support. There
 are 63 UH-1N aircraft in the inventory. They were built with an estimated service life of 10,000 flight hours and are not service limited due to on-going modifications and upgrades. There are 28 TH-1H aircraft in
 the inventory. They are used in the helicopter track for USAF Specialized Undergraduate Pilot Training. The TH-1H modernization modification provided a service life of 20 years, the last one was delivered in
 2013.

 This funding will address aircraft modifications, aging fleet problems to include: structural repairs, replacement of key systems based on structural fatigue, system obsolescence and a diminishing manufacturing
 industrial base. Additionally, this effort will address safety requirements to include: Federal Aviation Administration, DoD, engineering mandates and configuration changes. This effort includes funding for
 program support costs.

 The FY 2026 request was reduced by $0.084 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222,
 "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."

 Funding may be used to address Diminishing Manufacturing Sources (DMS) issues.

 Funding in this exhibit is contained in PE 0101235F, PE 0401314F, and PE 0804747F.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":80,"src_title":"H-1","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Aircraft Procurement Vol II.pdf$$, 603, 603, $$c785d74e93fc54b6$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L074$$, 2026, $$FY26 procurement funding acquires and installs various upgrades and enhancement modifications for the three (3) RC-135S COBRA BALL aircraft performing Air Combat Command (ACC) directed operational
 missions. Due to the rapidly changing global threat environment, the acquisition program manager has the authority to redirect funding as necessary to meet current stated and emerging Combatant Command
 (CCMD) and Intelligence Community (IC) requirements.

 The Capability Description Document (CDD) addresses airframe, sensor, navigation, communications, data link, and processing requirements necessary to keep the RC-135 fleet viable through 2050. A Program
 Management Directive (PMD) provides direction to the 645th Aeronautical Systems Group (645 AESG) for the acquisition and sustainment of the weapons system, associated mission support equipment, and
 processing, exploitation and dissemination tools.

 The RC-135S COBRA BALL program--Defense Airborne Reconnaissance Program (DARP)/Manned Reconnaissance Systems is managed in accordance with an incremental baseline upgrade acquisition
 strategy in order to maintain collection parity with evolving and emerging adversarial weapons systems utilized by state and non-state actors. The 645 AESG Baseline upgrade strategy requires purchase
 agreements for long-lead items that take approximately 10 to 12 months from contract award to delivery. Items required for integration in a given Baseline upgrade are contracted for purchase in the first year of
 the procurement funding cycle and are acquired and installed in the subsequent year. This acquisition strategy has been successful in maintaining critical combat capability in the Intelligence, Surveillance, and
 Reconnaissance (ISR) arena over the last 50 years.

 FY26 procurement funding efforts will concentrate on integration and testing of COBRA BALL Baseline 14 enhancements and long lead items for Baseline 15. Baseline 14 subsystem upgrades consist of but are
 not limited to: Foreign Instrumentation Signals Intelligence (FISINT) Direction Finding antenna, high-gain steerable-beam K-band collection antenna, and Digital Data Recording, Digital Search, enhanced signal
 identification and classification, Target Discrimination via SATCOM, and the integration of the RIVET JOINT Baseline 14 communications intelligence (COMINT) suite.

 Funding for this exhibit contained in PE 0305207F

 Milestone/Development Status

 FY26 procurement funding is associated with the acquisition, integration, and testing of Baseline 14. Funding provides logistical support efforts for the Baseline 14 configuration upgrades and enhancements on
 the three (3) RC-135S COBRA BALL aircraft, their sensor systems, and associated ground support systems. These upgrades are attributed to the research and development efforts initiated in FY 2023 and FY
 2024.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":74,"src_title":"RC-135","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Aircraft Procurement Vol II.pdf$$, 566, 566, $$47a1a0519a3d66a7$$, $$2026-05-10T04:06:02.992954+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L081$$, 2026, $$The MH-139A program will replace the Air Force fleet of UH-1N aircraft, which have significant capability gaps in speed, range, endurance, payload capacity, and aircraft self-protection. The program of record
 is 56 aircraft, including 8 total Aircrew Training Devices (ATDs), and associated support equipment. The replacement aircraft will provide a vertical airlift and support the requirements for Air Force Global Strike
 Command (AFGSC) and Air Force Reserve Command (AFRC). AFGSC is the Air Force lead command and operational capability requirements sponsor. This program is an element of the Air Force's nuclear
 enterprise reform initiatives.

 MH-139A Low-Cost Modifications encompass, but are not limited to, efforts to implement performance enhancements, product improvement solutions, and the associated test efforts, to resolve capability gaps
 and meet emerging requirements for the MH-139A aircraft and associated training systems as well as necessary efforts to improve reliability, maintainability, safety, and mission performance, to reduce logistics
 costs, and to improve cryptographic modernizations. Modifications are prioritized in coordination with the user based on the safety of flights, critical to the mission, or mission enhancement.

 This funding will support potentially Diminishing Manufacturing Sources (DMS) and obsolescence solutions, including, if optimal, life-of-type buys or bridge buys limited to the program of record quantity. Program
 funding includes, but is not limited to, the purchase of Government Furnished Equipment, Trainers, Pub/Tech Data, Interim Contractor Support, Interim Supply Support, Data, and Program costs needed to field
 the capability. MH-139A Low-Cost Modifications may include installation costs depending upon the modification.

 Funding for this exhibit contained in PE 0102110F.

 In accordance with Section 1815 of the FY 2008 National Defense Authorization Act (P.L. 110-181), this item is necessary for use by the active and reserve components of the Armed Forces for homeland
 defense missions, domestic emergency responses, and providing military support to civil authorities.

 Justification:
 This program, P-3A Mod H139A3, Gun Mount Modification, is a new start.

 This FY 2026 funding supports Engineering Change Proposal (ECPs), Correction of Deficiencies (CODs), Diminishing Manufacturing Sources (DMS), and Performance Improvements to delivered aircraft.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":81,"src_title":"MH-139A Mod","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Aircraft Procurement Vol II.pdf$$, 609, 609, $$ef5bb646386e321b$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L086$$, 2026, $$This line item funds multiple modifications that apply to weapon systems funded at less than 2 million per year as well as weapon systems with much greater budgets. The overall goal of the modifications
 budgeted is to enhance capability and improve reliability and maintainability.

 Mobility Air Forces (MAF) Training supports the modification and enhancement of high fidelity MAF aircrew training and support systems to meet combat readiness needs, to include efforts to ensure full
 employment of Distributed Mission Operations (DMO) capabilities.

 TDL Communications Capabilities: The Multi-functional Information Distribution system (MIDS) Modernization is a continuous technology development/acquisition strategy for robust interoperable
 communications for MIDS Joint Tactical Radio System (JTRS) hosted waveforms. The current phase of this capability is a Link 16 enhancement to the MIDS JTRS known as Block Upgrade 3 (BU3). The
 modernized capability implements the required software and firmware updates necessary to meet the Joint Combatant Commander's prioritized requirements for Integrated Fire Control and Joint Tactical Grid
 information exchange requirements at the Tactical Edge. Upgrades to current fielded terminals began in FY23. Procurement of new communication capabilities & integration as well as other mods, components,
 and related provisioning supplies to include interim contract support. Procurement of communication equipment will be in support of Protected Tactical Waveform and Agile communication programs at
 a minimum. Funding will also support procurement of other communication capabilities, such as Link 16, and networking equipment with a focus on achieving an operationally-optimized Advanced Battle
 Management System and Joint All Domain Command and Control. Funding for this exhibit contained in PE 0207448F.

 Advanced Targeting Pods (ATPs) provide long-range target acquisition and expanded weapon delivery envelopes for greater aircraft survivability which are imperative in supporting Long Range Kill Chain,
 NTISR, as well as target identification, reduction in collateral damage, and fratricide prevention for F-15C/E/EX, F-16 (all blocks), A-10C, B-52H, B-1B. ATP expanded range capabilities (in all domains), such
 as high resolution imagery, larger aperture, eye safe laser, high system reliability and smaller deployment footprint provide greater combat effectiveness across several mission areas. Demonstrated capability
 to support cUAS and Homeland Missile Defense missions. Each targeting pod provides long-range target acquisition and expanded weapon delivery envelopes during day, night, and all-weather conditions.
 Targeting pods are equipped with infrared (Longwave/Midwave/Shortwave Infrared, Color TV) sensor, laser designator, digital video, and real-time video data link for connectivity with ground forces. Increased
 funding to ATPs is in support of the Bandwidth Efficient-Common Datalink (BE-CDL)/Type-1 Encryption OSD mandate (Crypto Mod). implementation and fielding. Failure to fund BE-CDL will impact ability of the
 warfighter to securely communicate in the battlespace.

 Battlefield Airborne Communications Node (BACN): No FY2026 funding requested.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":86,"src_title":"Other Aircraft","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Aircraft Procurement Vol II.pdf$$, 663, 663, $$8008b9c539f14f28$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L087$$, 2026, $$The Secretary of Defense's Nunn-McCurdy decision on July 8, 2024 recertified the LGM-35A Sentinel program. The Milestone Decision Authority rescinded the 2020 Milestone B decision which allows the
 Program Office to focus on the reassessment and refinement of requirements as they translate to system specifications, technical maturation of the system design, and cost and schedule risk mitigation
 strategies. The Program Office will work with stakeholders to update program requirements, quantities, and milestones to align with the outcomes of the reassessments and refinements.

 LGM-35A Sentinel Secondary Launch Platform - Airborne (SLP-A) provides an air-based, secondary launch system design configurable to command either a Minuteman III (MMIII) or Sentinel weapon system
 in order to maintain U.S. strategic nuclear deterrence. The LGM-35A Sentinel Capability Development Document required LGM-35A Sentinel provide a dual-capable SLP-A design which provides flexibility as a
 direct replacement for the MM III Airborne Launch Control System to mitigate USSTRATCOM operational risk associated with age out of classified hardware components.

 Two incremental kit deliveries are planned to meet USSTRATCOM operational requirements. The initial baseline SLP-A capability provides two-way voice, one-way data, and Line-of-Sight (LOS) launch for MM
 IIII weapon systems. Upgrade to full Sentinel capability adds two-way voice, two-way data, Emergency Action Message relay capability, and a beyond-LOS (BLOS) launch capability for the Sentinel weapon
 system. The total SLP-A design is based on a modular open-system architecture which maintains commonality with the Sentinel ground system to leverage the Sentinel Common Crypto design effort for NSA
 cryptographic certification, facilitate ease of integration aboard 16 Navy E-6B aircraft, and be re-hostable to accommodate future SLP-A platform(s).$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":87,"src_title":"Other Aircraft","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Aircraft Procurement Vol II.pdf$$, 689, 689, $$4c92dbcb9745205f$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L082$$, 2026, $$The HH-60G currently supports the Air Force's core function of Personnel Recovery. The primary mission of the HH-60G is to conduct day, night, and marginal weather Combat Search and Rescue (CSAR)
 in order to recover isolated personnel in hostile or permissive environments. Potential mission areas include casualty evacuation (CASEVAC), medical evacuation (MEDEVAC), non-combatant evacuation
 operations, civil search and rescue, international aid, disaster humanitarian relief, and insertion/extraction of combat forces.$$, $$$$, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":82,"src_title":"H-60","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Aircraft Procurement Vol II.pdf$$, 611, 611, $$77fcac71980fe03d$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_0360_L002$$, 2027, $$Procurement line item: Defense Production Act Purchases.

