INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L106$$, 2026, $$This effort supports Post Production support efforts for the C-17. These funds are required to effectively perform aircraft maintenance at Organizational and Intermediate (O&I) levels of aircraft maintenance at
 Main Operating Bases (MOBs), Avionics Regional Maintenance Centers (RMCs), Engine RMCs, Enroute locations, Backshop activities, plus requirements in support of the Analytical Condition Inspections.

 The areas of focus include, but are not limited to:

 - The Engine Depot Stock & Preservation Kit buy provides investment-funded engine depot replenishment spares to support depot operations.

 - Purchase of Peculiar and Common Support Equipment for the C-17 (PSE and CSE). CSE is comprised of support equipment used by the C-17 and other programs, while PSE is unique to the C-17. Both are
 required to effectively perform aircraft maintenance at Organizational and Intermediate (O&I) levels of aircraft maintenance at Main Operating Bases (MOBs), Avionics Regional Maintenance Centers (RMCs),
 Engine RMCs, Enroute locations, Backshop activities, plus requirements in support of the Analytical Condition Inspections

 - Materiel Improvement Program (MIP) projects. MIP projects correct Deficiency Report (DR) issues that were discovered during the aircraft production phase. There have been over 275 projects incorporated
 into production aircraft. Approximately 3 projects remain to be retrofitted to post production aircraft to bring them up to production aircraft configuration. The remaining projects are TCTO -1695 (7 installations),
 TCTO -2031 (107 installations) and TCTO-2133 (87 installations), equating to a 201 total USAF installations. The projects are worked in conjunction with aircraft heavy maintenance (depot) cycle every 6 years.

 This modification supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D.

 Funding may be used to address Diminishing Manufacturing Sources (DMS) issues. Funding for this exhibit is contained in PE 0401130F.

 Justification:
 This program, Category Uncategorized Item Material Improvement Program (MIP), is a new start.
 This program, Category Uncategorized Item Engine Depot Stock and Preservation Kit Buy, is a new start.
 This program, Category Uncategorized Item Peculiar Ground Support Equipment (PSE), is a new start.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":106,"src_title":"C-17A","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Aircraft Procurement Vol I.pdf$$, 227, 227, $$66088117360f6ea1$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L107$$, 2026, $$The CV-22 is the US Air Force Special Operations Forces (SOF) variant of the joint multi-mission V-22 tilt-rotor aircraft. The aircraft provides long-range infiltration, exfiltration, personnel recovery, and re-supply
 of SOF in politically sensitive and hostile/denied areas. The Navy is the lead service for the joint V-22 program and has overall responsibility for managing all V-22 variants, including the Air Force CV-22 variant.

 CV-22 post production support funding enables the seamless transition from the production phase of the program to the operations and support (O&S) phase. Post Production support funding is required to
 procure support equipment and integrated logistics support (ILS) requirements affiliated with sustainment of CV-22 modifications to improve operational effectiveness, readiness, and aircraft availability of the
 worldwide CV-22 fleet.

 Funding for this exhibit contained in PE 0401318F.

 Funding may be used to address Diminishing Manufacturing Sources (DMS) issues.

 Justification:
 No FY 2026 discretionary funding requested.

 The FY 2026 request for CV-22 includes $0 thousand of discretionary and $7,085 thousand of mandatory (reconciliation) for a total of $7,085 thousand. The mandatory funds Peculiar Support Equipment,
 Simulator Support, and Production Integrated Logistic Support. Further information for this reconciliation request is provided in Section 20007 (Air Superiority) of the Reconciliation Exhibit.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":107,"src_title":"CV-22 Post Production Support","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Aircraft Procurement Vol I.pdf$$, 229, 229, $$4f147c9b2db158b0$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L114$$, 2026, $$The F-16 is a multi-role fighter that comprises roughly 40% of the USAF fighter fleet with over 830 aircraft supporting a variety of air-to-air and air-to-surface missions, such as offensive and defensive counterair,
 close air support, forward air control, air interdiction (day/night and all-weather) and Suppression of Enemy Air Defenses (SEAD)/Destruction of Enemy Air Defenses (DEAD). F-16 posture and readiness
 combined with low operating costs deliver affordable capacity for the USAF and partner nations. Its capabilities continue to evolve, capitalizing upon advancements made in computers, avionics systems,
 engines, and structural technologies. These advancements meet emerging warfighter requirements to combat current and evolving enemy threats.

 This request will provide funding for F-16 support equipment, facilities support, interim contractor support and production tooling storage management.

 In FY25, a Congressional Add provided a $50M increase in order to procure F-16 Simulators for ANG.

 Funding for this exhibit is contained in PE 0207133F$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":114,"src_title":"F-16 Post Production Support","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Aircraft Procurement Vol I.pdf$$, 237, 237, $$714a6504000d95c7$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L115$$, 2026, $$This effort procures necessary support equipment for a simulation environment. The battlespace environment and the computing infrastructure to implement the battlespace is referred to as Joint Simulation
 Environment (JSE) in a box.

 Funding for this exhibit is contained in PE 0207138F.

 Justification:
 No FY 2026 funding is requested.

 FY 2024 funding procured the production and integration of F-22 In a Box (IAB) systems including Hardware (HW), all required Software (SW) licenses, and SW build to deliver a complete F-22 IAB system to the
 Virtual Test & Training Center (VTTC), Nellis AFB, Las Vegas, Nevada. An F-22 IAB system includes the cockpit, Hands-On-Throttle And Stick (HOTAS), landing gear panel, Cockpit Support Rack (CSR), spares,
 appropriate SW licenses, and current SW build.

 Funding allows these systems to operate within the JSE environment to provide "Night-1" capability and high end integrated advanced tactics, test, and training. It will also ensure the capabilities developed
 through the operational imperatives can be rapidly incorporated into warfighting concepts of employment (CONEMPs).

 Funding may be used to resolve emerging safety of flight and DMS issues, accommodate technology insertion, respond to field support equipment issues, and fulfill Federal Aviation Administration (FAA) or other
 mandates to ensure continued aircrew safety maintenance capability and mission effectiveness.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":115,"src_title":"F-22A","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Aircraft Procurement Vol I.pdf$$, 241, 241, $$038d8e1aa2efabd0$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L116$$, 2026, $$Funding is for the procurement of various Platform-in-a-Box (PIAB) and platform specific battlestation training equipment to include, but not limited to, hardware, software, licenses, peripheral equipment and
 sub-systems, visual display system, inital spares, and the integration of those systems into the Joint Simulation Environment (JSE) battlespace. PIABs and battlestations will be used at various Joint Integrated
 Test & Training Center (JITTC) locations including, but not limited to; Nellis AFB (JITTC-N) and Joint Base Elmendorf-Richardson (JITTC-E), leveraging the JSE. PIABs and battlestations will support training
 operations, large force exercises, and local small force events. The intent is to replicate and expand the current digital test & training range capabilities allowing multiple dissimilar PIABs and battlestations to
 operate in a common environment without concern for airspace constraints, threat density, and outside surveillance, while protecting friendly capability Tactics, Techniques, and Procedures (TTPs) and future
 capabilities.

 JSE leverages 5th+ Generation Operational Test and Evaluation (OT&E) capability to improve TTPs in an operationally relevant environment. JITTCs support large force exercises and the United States Air
 Force Warfare Center (USAFWC), Weapons Instructor Course (WIC) syllabus through Weapon School Integration (WSINT). The high-fidelity simulator training to be provided by JSE improves the throughput
 capacity of Formal Training Unit (FTU) and joint war fighter tactical readiness. Funding may also be used to address Diminishing Manufacturing Sources (DMS) issues, obsolescence resolution and similar
 emerging requirements, as well as overarching programmatic support. This requirement (or modification) supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D.
 Funding for this exhibit is contained in PE 0207606F.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"title_fuzzy_same_ba","rapidfuzz_score":81.5,"src_li":117,"src_title":"Joint Simulation Environment Post Production Support","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Aircraft Procurement Vol I.pdf$$, 247, 247, $$df7f2b2c8ba206f6$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
